 402→        users!sender_id(name, user_email, image_url, id, badge)
 403→        `)
 404→    .eq('receiver_id', receiverId)
 405→    .eq('read', false)
 406→    .order('created_at', {ascending: false})
 407→    .order('id', {ascending: false})
 408→    .limit(fetchLimit)
 409→
 410→    if(before){
 411→        journalQuery = journalQuery.lt('created_at', before);
 412→        opinionQuery = opinionQuery.lt('created_at', before);
 413→    }
 414→
 415→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 416→
 417→    if(journalResult.error){
 418→        console.error('supabase error:', journalResult.error.message);
 419→        return res.status(500).json({error: 'supabase error while getting unread notification'})
 420→    }
 421→    if(opinionResult.error){
 422→        console.error('supabase error:', opinionResult.error.message);
 423→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
 424→    }
 425→
 426→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 427→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 428→
 429→    const merged = [...journalNotifs, ...opinionNotifs]
 430→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 431→
 432→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 433→
 434→    let hasLikedResult = [];
 435→    let hasBookMarkedResult = [];
 436→    if(journalIds.length > 0){
 437→        const [hasLiked, hasBookMarked] = await Promise.all([
